	issueFileName += TEXT(".xml");
	pathAppend(filePath, issueFileName);
	_doNppLogNetworkDriveIssue = (PathFileExists(filePath.c_str()) == TRUE);
	if (!_doNppLogNetworkDriveIssue)
	{
		filePath2 = _userPath;
